insert into projects (
  id, code, title, stars, level, duration_quarters, min_reputation,
  revenue, cost, reputation_impact, client_brief, cost_breakdown,
  bonus_condition, fail_condition, execution_teams, sales_requirement,
  available_from_quarter, available_to_quarter, published
) values
('PRJ-001', 'PRJ-001', 'New Manager Induction Programme', 1, 1, 1, 0, 18000, 9000, 5, 'A regional logistics firm needs a one-day induction programme for newly promoted managers. Content covers leadership basics, company culture, and performance expectations.', 'Facilitation: $4,000 - Materials: $3,000 - Admin: $2,000', 'Deliver on time for +3 extra reputation.', 'Late delivery results in -5 reputation and 20% revenue penalty.', '["ld"]'::jsonb, '{"type":"specialist","count":1}'::jsonb, 1, 8, true),
('PRJ-002', 'PRJ-002', 'Customer Service Skills Workshop', 1, 1, 1, 0, 22000, 11000, 5, 'A retail chain requests a half-day customer service skills workshop for 40 front-line staff. Focus on communication, complaint handling, and brand representation.', 'Facilitation: $5,000 - Workbooks: $3,000 - Venue support: $3,000', 'Client satisfaction score above 4.5/5 earns a $2,000 bonus.', 'Low satisfaction (<3.5/5) results in -5 reputation.', '["ld"]'::jsonb, '{"type":"specialist","count":1}'::jsonb, 1, 8, true),
('PRJ-003', 'PRJ-003', 'Digital Onboarding E-Learning Suite', 2, 2, 2, 10, 48000, 21600, 10, 'A fintech company wants to replace their paper-based onboarding with a three-module e-learning suite. Modules cover compliance, tools training, and company values.', 'Instructional design: $8,000 - E-Learning build: $10,000 - Studio assets: $3,600', 'All three modules approved on first review earns +5 reputation.', 'Missing any module by the deadline results in -10 reputation and 30% revenue penalty.', '["ld","elearning"]'::jsonb, '{"type":"specialist","count":1}'::jsonb, 1, 10, true),
('PRJ-004', 'PRJ-004', 'Leadership Development Curriculum', 2, 2, 2, 10, 52000, 23400, 10, 'A healthcare group commissions a three-part leadership development curriculum for senior nurses moving into management. Covers strategic thinking, people management, and change leadership.', 'Curriculum design: $10,000 - Facilitation: $8,000 - Assessment tools: $5,400', 'Participants rate the programme 4.7+ earns +8 reputation.', 'Incomplete curriculum delivery results in -8 reputation.', '["ld"]'::jsonb, '{"type":"specialist","count":1}'::jsonb, 2, 11, true),
('PRJ-007', 'PRJ-007', 'Team Building & Engagement Event', 2, 2, 1, 5, 32000, 14400, 8, 'A client wants a team-building event for 100 employees. They need the event documented with a videographer and photographer, and they request a trainer to facilitate the day.', 'Trainer: $5,000 - Media coverage: $4,400 - Materials: $5,000', 'Excellent feedback earns +5 reputation.', 'Logistics delays cost -3 reputation.', '["gamification","resources"]'::jsonb, '{"type":"specialist","count":1}'::jsonb, 1, 12, true),
('PRJ-005', 'PRJ-005', 'National Sales Capability Programme', 3, 3, 3, 50, 82000, 27060, 20, 'A multinational FMCG company needs a blended sales capability programme for 200 regional sales managers across five countries. Includes e-learning modules, virtual workshops, and field coaching guides.', 'Programme design: $10,000 - E-Learning: $8,000 - Studio: $4,000 - Facilitation: $5,060', 'On-time completion across all regions earns +15 reputation and a $5,000 bonus.', 'Missing regional rollout by deadline incurs -15 reputation and 25% revenue penalty.', '["ld","elearning"]'::jsonb, '{"type":"consultant","count":1}'::jsonb, 4, 14, true),
('PRJ-008', 'PRJ-008', 'Procurement-Heavy Public Tender', 3, 3, 3, 50, 88000, 26400, 18, 'A government agency has issued a multi-vendor tender for a workforce capability programme with strict procurement and compliance requirements.', 'Tender design: $10,000 - Compliance: $6,400 - Delivery: $10,000', 'Full compliance + on-time delivery earns +12 reputation.', 'Any compliance miss results in -10 reputation.', '["procurement","ld"]'::jsonb, '{"type":"consultant","count":1}'::jsonb, 5, 14, true),
('PRJ-006', 'PRJ-006', 'Enterprise Learning Transformation Programme', 4, 4, 4, 100, 480000, 120000, 40, 'A global bank wants to transform its entire learning function across 12 countries. The scope includes strategy design, LMS implementation, content migration, capability frameworks, a gamified leadership academy, and a full measurement and evaluation system.', 'Strategy: $30,000 - LMS: $25,000 - Content: $20,000 - Gamification: $15,000 - Ops: $20,000 - QA: $10,000', 'Full delivery and board sign-off earns +30 reputation and $30,000 bonus.', 'Any major milestone missed results in -25 reputation and contract termination.', '["ld","elearning","gamification","operations"]'::jsonb, '{"type":"consultant","count":2}'::jsonb, 8, 20, true),
('PRJ-009', 'PRJ-009', 'Test', 2, 2, 1, 20, 20000, 8000, 20, 'This is a test project to see if the feature working properly', '', '', '', '["gamification","resources","studio","elearning"]'::jsonb, '{"type":"consultant","count":1}'::jsonb, 1, 20, true)
